import React, { useState } from "react";

const FIELDS = [
  "SUMMARY",
  "EDUCATION",
  "COMPETENCIES",
  "EXPERIENCE",
  "PROJECTS",
  "CERTS"
];

export default function App() {
  const [field, setField] = useState("SUMMARY");
  const [text, setText] = useState("");
  const [loading, setLoading] = useState(false);
  const [backendUrl, setBackendUrl] = useState("http://localhost:4000");

  async function handleGenerate(e) {
    e.preventDefault();
    setLoading(true);
    try {
      const payload = { field, text };
      const res = await fetch(`${backendUrl}/api/inject`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ replacements: { [field]: text } })
      });
      if (!res.ok) {
        const err = await res.json();
        alert("Error: " + (err.error || JSON.stringify(err)));
        setLoading(false);
        return;
      }
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "custom_resume.pdf";
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      alert("Network error: " + err.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{ padding: 20, fontFamily: "Arial, sans-serif", maxWidth: 800, margin: "auto" }}>
      <h2>Auto Resume Builder — Direct Inject</h2>
      <p>Paste the exact text you want to appear in the yellow-highlighted area. Choose which area (e.g., SUMMARY, EXPERIENCE).</p>

      <div style={{ marginBottom: 8 }}>
        <label>Backend URL: </label>
        <input value={backendUrl} onChange={e => setBackendUrl(e.target.value)} style={{ width: 300 }} />
        <small style={{ marginLeft: 8, color: "#666" }}>e.g. http://localhost:4000</small>
      </div>

      <div style={{ marginBottom: 8 }}>
        <label>Field: </label>
        <select value={field} onChange={e => setField(e.target.value)}>
          {FIELDS.map(f => <option key={f} value={f}>{f}</option>)}
        </select>
      </div>

      <form onSubmit={handleGenerate}>
        <textarea
          value={text}
          onChange={e => setText(e.target.value)}
          rows={12}
          style={{ width: "100%", padding: 8 }}
          placeholder="Paste the exact text that should replace the yellow-highlighted area. Newlines are preserved."
        />
        <div style={{ marginTop: 10 }}>
          <button type="submit" disabled={loading}>{loading ? "Generating..." : "Generate PDF"}</button>
        </div>
      </form>
    </div>
  );
}
